// Pass through on Hunter error so the pipeline continues.
const record = $('Split Into Items').item.json;
return [{ json: { ...record, hunter_error: true } }];

// Prioritize personal email of the agent by title rank.
const emails = $input.item.json.data?.emails || [];
const PRIORITY = ['owner','agent','realtor','broker','ceo','president','manager'];

let best = null;
for (const title of PRIORITY) {
  best = emails.find(e => (e.position || '').toLowerCase().includes(title));
  if (best) break;
}
if (!best && emails.length > 0) best = emails[0];

const record = $('Split Into Items').item.json;
return [{ json: {
  ...record,
  contact_email: best?.value || null,
  contact_name: best ? [best.first_name, best.last_name].filter(Boolean).join(' ') : null,
  hunter_confidence: best?.confidence || null
} }];

const people = $input.item.json.people || [];
const PRIORITY = ['real estate agent', 'realtor', 'broker', 'owner'];

let best = null;
for (const title of PRIORITY) {
  best = people.find(p => (p.title || '').toLowerCase().includes(title));
  if (best) break;
}
if (!best && people.length > 0) best = people[0];

const prev = $('Extract Best Email').item.json;
return [{ json: {
  ...prev,
  contact_name: best ? [best.first_name, best.last_name].filter(Boolean).join(' ') : prev.contact_name,
  mobile_phone: best?.sanitized_phone || best?.phone_numbers?.[0]?.sanitized_number || null
} }];

const r = $input.item.json;
const nameParts = (r.contact_name || r.agent_name || '').split(' ');
const firstName = nameParts[0] || '';
const lastName = nameParts.slice(1).join(' ') || '';

return [{ json: {
  ...r,
  hs_firstname: firstName,
  hs_lastname: lastName
} }];

// 409 = contact already exists — extract the existing contact ID.
const error = $input.item.json;
const existingId = error.message?.match(/existing ID: (\d+)/)?.[1] || null;
return [{ json: { ...$('Prepare HubSpot Fields').item.json, hubspot_contact_id: existingId, is_duplicate: true } }];

const deal = $input.item.json;
const prev = $('Set Contact ID').item.json;
return [{ json: { ...prev, hubspot_deal_id: deal.id || null } }];

const slackUrl = $env.SLACK_WEBHOOK_URL;
if (!slackUrl) return [{ json: { skipped: true } }];
const r = $input.item.json;
const chatBadge = r.has_live_chat ? '✅ Has chat' : '❌ No live chat';
return [{ json: { slackUrl, slackBody: { text: `🏠 *New RE Agent — Pushed to CRM*
${r.agent_name} @ ${r.agency_name || 'Independent'} — Score: ${r.ai_score}/10
📍 ${r.city}, ${r.state} ${r.zip_code}
${chatBadge}${r.response_time_minutes ? ` | ⏱ ${r.response_time_minutes}min response` : ''}
📞 ${r.phone || 'N/A'} | 📱 ${r.mobile_phone || 'N/A'}
📧 ${r.contact_email || 'N/A'}
🌐 ${r.website || 'N/A'}
Why: ${r.ai_signals}` } } }];

const slackUrl = $env.SLACK_WEBHOOK_URL;
if (!slackUrl) return [{ json: {} }];
const err = $input.item.json;
return [{ json: { slackUrl, slackBody: { text: `🚨 *RE Workflow E Error*\n${err.execution?.error?.message || 'Unknown error'}` } } }];
